module memory_4x4 (
        input [1:0] addr,
        input [3:0] data_in,
        input we,
        input clk,
        output reg [3:0] data_out);

    reg [3:0] obf_mem [3:0];

    always @(posedge clk) begin
        if (we)
            obf_mem[addr] <= data_in;
        data_out <= obf_mem[addr];
    end

endmodule
